## Steps to reproduce the issue
Execute the following command using the following code. yosys version is `Yosys 0.17+5 (git sha1 UNKNOWN, clang 3.9.1-19ubuntu1 -fPIC -Os)`

`yosys -p "read_verilog InterleavedPicker.v; proc; opt_muxtree; opt_clean; write_verilog -noattr out.v"`

InterleavedPicker.v ([Original](https://github.com/rsd-devel/rsd/blob/8777d59e0b9aa06e4df06711d00754a2f8a51d8b/Processor/Src/Primitives/Picker.sv#L55-L91)): 
```verilog
module InterleavedPicker (
	req,
	grant,
	grantPtr,
	granted
);
	parameter ENTRY_NUM = 4;
	parameter GRANT_NUM = 2;
	input wire [ENTRY_NUM - 1:0] req;
	output reg [ENTRY_NUM - 1:0] grant;
	output reg [(GRANT_NUM * $clog2(ENTRY_NUM)) - 1:0] grantPtr;
	output reg [0:GRANT_NUM - 1] granted;
	localparam INDEX_BIT_SIZE = $clog2(ENTRY_NUM);
	reg [ENTRY_NUM - 1:0] reqTmp;
	always @(*) begin : sv2v_autoblock_1
		reg [0:1] _sv2v_jump;
		_sv2v_jump = 2'b00;
		reqTmp = req;
		grant = 1'sb0;
		begin : sv2v_autoblock_2
			reg signed [31:0] p;
			begin : sv2v_autoblock_3
				reg signed [31:0] _sv2v_value_on_break;
				for (p = 0; p < GRANT_NUM; p = p + 1)
					if (_sv2v_jump < 2'b10) begin
						_sv2v_jump = 2'b00;
						granted[p] = 1'sb0;
						grantPtr[((GRANT_NUM - 1) - p) * $clog2(ENTRY_NUM)+:$clog2(ENTRY_NUM)] = 0;
						begin : sv2v_autoblock_4
							reg signed [31:0] e;
							begin : sv2v_autoblock_5
								reg signed [31:0] _sv2v_value_on_break;
								reg [0:1] _sv2v_jump_1;
								_sv2v_jump_1 = _sv2v_jump;
								for (e = p; e < ENTRY_NUM; e = e + GRANT_NUM)
									if (_sv2v_jump < 2'b10) begin
										_sv2v_jump = 2'b00;
										if (reqTmp[e]) begin
											grant[e] = 1'sb1;
											granted[p] = 1'sb1;
											grantPtr[((GRANT_NUM - 1) - p) * $clog2(ENTRY_NUM)+:$clog2(ENTRY_NUM)] = e;
											reqTmp[e] = 1'sb0;
											_sv2v_jump = 2'b10;
										end
										_sv2v_value_on_break = e;
									end
								if (!(_sv2v_jump < 2'b10))
									e = _sv2v_value_on_break;
								if (_sv2v_jump != 2'b11)
									_sv2v_jump = _sv2v_jump_1;
							end
						end
						_sv2v_value_on_break = p;
					end
				if (!(_sv2v_jump < 2'b10))
					p = _sv2v_value_on_break;
				if (_sv2v_jump != 2'b11)
					_sv2v_jump = 2'b00;
			end
		end
	end
endmodule
```

The output code is shown below.
```verilog
module InterleavedPicker(req, grant, grantPtr, granted);
  wire [3:0] _00_;
  wire [1:0] _01_;
  wire [1:0] _02_;
  wire _03_;
  wire _04_;
  wire _05_;
  wire _06_;
  wire [1:0] _07_;
  wire _08_;
  wire [1:0] _09_;
  wire [1:0] _10_;
  wire [1:0] _11_;
  wire _12_;
  wire [1:0] _13_;
  wire _14_;
  wire [1:0] _15_;
  wire _16_;
  wire [1:0] _17_;
  wire _18_;
  wire _19_;
  wire _20_;
  wire _21_;
  output [3:0] grant;
  wire [3:0] grant;
  output [3:0] grantPtr;
  reg [3:0] grantPtr;
  output [0:1] granted;
  reg [0:1] granted;
  input [3:0] req;
  wire [3:0] req;
  always @*
    if (_18_) grantPtr[1:0] = _00_[1:0];
  always @*
    if (!1'h0) grantPtr[3:2] = _00_[3:2];
  always @*
    if (_18_) granted[0] = _01_[0];
  always @*
    if (!1'h0) granted[1] = _01_[1];
  assign _18_ = _07_ < 2'h2;
  assign _19_ = _09_ < 2'h2;
  assign _20_ = _17_ < 2'h2;
  assign _21_ = _10_ != 2'h3;
  assign _01_[0] = _20_ ? _04_ : _16_;
  assign _00_[1:0] = _20_ ? _02_ : _15_;
  assign _05_ = _20_ ? _06_ : 1'h0;
  assign _17_ = req[1] ? 2'h2 : 2'h0;
  assign _15_ = req[1] ? 2'h1 : 2'h0;
  assign _16_ = req[1] ? 1'h1 : 1'h0;
  assign _03_ = req[1] ? 1'h1 : 1'h0;
  assign grant[3] = _18_ ? _05_ : 1'h0;
  assign grant[1] = _18_ ? _03_ : 1'h0;
  assign _07_ = _21_ ? 2'h0 : _10_;
  assign _13_ = req[2] ? 2'h2 : 2'h0;
  assign _11_ = req[2] ? 2'h2 : 2'h0;
  assign _12_ = req[2] ? 1'h1 : _08_;
  assign _14_ = req[2] ? 1'h1 : 1'h0;
  assign _10_ = _19_ ? _13_ : _09_;
  assign _01_[1] = _19_ ? _12_ : _08_;
  assign _00_[3:2] = _19_ ? _11_ : 2'h0;
  assign grant[2] = _19_ ? _14_ : 1'h0;
  assign _09_ = req[0] ? 2'h2 : 2'h0;
  assign _08_ = req[0] ? 1'h1 : 1'h0;
  assign grant[0] = req[0] ? 1'h1 : 1'h0;
  assign _02_ = req[3] ? 2'h3 : _15_;
  assign _04_ = req[3] ? 1'h1 : _16_;
  assign _06_ = req[3] ? 1'h1 : 1'h0;
endmodule
```

Interpreting the output circuit, we see that `granted[1]` is synthesized as a combinational circuit as follows.
```verilog
assign granted[1] = ((req[0] ? 2'h2 : 2'h0) < 2'h2) ?
  (req[2] ? 1'h1 : (req[0] ? 1'h1 : 1'h0)) :
  (req[0] ? 1'h1 : 1'h0);
```

## Expected behavior

Input `req = 4'b0001` for the output code, and `granted[1]` will be 0.

## Actual behavior

Input `req = 4'b0001` for the output code, and `granted[1]` will be 1.

This result was calculated manually. I checked this way because the expr command does not work.
`yosys -p "read_verilog InterleavedPicker.v; proc; opt_muxtree; opt_clean; eval -set req 1"`
```
5. Executing EVAL pass (evaluate the circuit given an input).
Eval result: \grant = 4'0001.
Failed to evaluate signal \grantPtr: Missing value for \grantPtr.
Failed to evaluate signal \granted: Missing value for \granted.
```

